import boto3
import json
import uuid
from datetime import datetime
from typing import Dict, Any, Optional, List
import hashlib
import hmac
import base64


class SQSPIIPublisher:
    def __init__(
        self,
        queue_url: str,
        region_name: str = 'us-east-1',
        aws_access_key_id: Optional[str] = None,
        aws_secret_access_key: Optional[str] = None,
        encryption_key: Optional[str] = None
    ):
        self.queue_url = queue_url
        self.encryption_key = encryption_key
        
        if aws_access_key_id and aws_secret_access_key:
            self.sqs_client = boto3.client(
                'sqs',
                region_name=region_name,
                aws_access_key_id=aws_access_key_id,
                aws_secret_access_key=aws_secret_access_key
            )
        else:
            self.sqs_client = boto3.client('sqs', region_name=region_name)
    
    def _encrypt_pii_field(self, value: str) -> str:
        if not self.encryption_key:
            return value
        
        key = self.encryption_key.encode()
        message = value.encode()
        signature = hmac.new(key, message, hashlib.sha256).digest()
        encrypted = base64.b64encode(signature + message).decode()
        return encrypted
    
    def _hash_pii_field(self, value: str) -> str:
        return hashlib.sha256(value.encode()).hexdigest()
    
    def _sanitize_phone_number(self, phone: str) -> str:
        return ''.join(filter(str.isdigit, phone))
    
    def _validate_email(self, email: str) -> bool:
        return '@' in email and '.' in email.split('@')[1]
    
    def create_user_message(
        self,
        user_id: str,
        email: str,
        phone_number: str,
        first_name: str,
        last_name: str,
        address: Dict[str, str],
        additional_data: Optional[Dict[str, Any]] = None,
        encrypt_pii: bool = True
    ) -> Dict[str, Any]:
        if not self._validate_email(email):
            raise ValueError(f"Invalid email format: {email}")
        
        sanitized_phone = self._sanitize_phone_number(phone_number)
        
        message = {
            'message_id': str(uuid.uuid4()),
            'timestamp': datetime.utcnow().isoformat(),
            'user_id': user_id,
            'pii_data': {
                'email': self._encrypt_pii_field(email) if encrypt_pii else email,
                'phone_number': self._encrypt_pii_field(sanitized_phone) if encrypt_pii else sanitized_phone,
                'first_name': self._encrypt_pii_field(first_name) if encrypt_pii else first_name,
                'last_name': self._encrypt_pii_field(last_name) if encrypt_pii else last_name,
                'address': {
                    'street': self._encrypt_pii_field(address.get('street', '')) if encrypt_pii else address.get('street', ''),
                    'city': self._encrypt_pii_field(address.get('city', '')) if encrypt_pii else address.get('city', ''),
                    'state': self._encrypt_pii_field(address.get('state', '')) if encrypt_pii else address.get('state', ''),
                    'zip_code': self._encrypt_pii_field(address.get('zip_code', '')) if encrypt_pii else address.get('zip_code', ''),
                    'country': address.get('country', 'US')
                }
            },
            'email_hash': self._hash_pii_field(email),
            'phone_hash': self._hash_pii_field(sanitized_phone)
        }
        
        if additional_data:
            message['additional_data'] = additional_data
        
        return message
    
    def publish_user_message(
        self,
        user_id: str,
        email: str,
        phone_number: str,
        first_name: str,
        last_name: str,
        address: Dict[str, str],
        additional_data: Optional[Dict[str, Any]] = None,
        encrypt_pii: bool = True,
        message_attributes: Optional[Dict[str, Any]] = None,
        delay_seconds: int = 0
    ) -> Dict[str, Any]:
        message = self.create_user_message(
            user_id=user_id,
            email=email,
            phone_number=phone_number,
            first_name=first_name,
            last_name=last_name,
            address=address,
            additional_data=additional_data,
            encrypt_pii=encrypt_pii
        )
        
        message_body = json.dumps(message)
        
        send_params = {
            'QueueUrl': self.queue_url,
            'MessageBody': message_body,
            'DelaySeconds': delay_seconds
        }
        
        if message_attributes:
            formatted_attributes = {}
            for key, value in message_attributes.items():
                if isinstance(value, str):
                    formatted_attributes[key] = {
                        'StringValue': value,
                        'DataType': 'String'
                    }
                elif isinstance(value, (int, float)):
                    formatted_attributes[key] = {
                        'StringValue': str(value),
                        'DataType': 'Number'
                    }
            send_params['MessageAttributes'] = formatted_attributes
        
        response = self.sqs_client.send_message(**send_params)
        
        return {
            'message_id': response['MessageId'],
            'md5_of_body': response['MD5OfMessageBody'],
            'user_message_id': message['message_id'],
            'timestamp': message['timestamp']
        }
    
    def publish_batch_user_messages(
        self,
        users: List[Dict[str, Any]],
        encrypt_pii: bool = True,
        batch_size: int = 10
    ) -> List[Dict[str, Any]]:
        results = []
        
        for i in range(0, len(users), batch_size):
            batch = users[i:i + batch_size]
            entries = []
            
            for idx, user in enumerate(batch):
                message = self.create_user_message(
                    user_id=user['user_id'],
                    email=user['email'],
                    phone_number=user['phone_number'],
                    first_name=user['first_name'],
                    last_name=user['last_name'],
                    address=user['address'],
                    additional_data=user.get('additional_data'),
                    encrypt_pii=encrypt_pii
                )
                
                entry = {
                    'Id': str(idx),
                    'MessageBody': json.dumps(message)
                }
                
                if 'message_attributes' in user:
                    formatted_attributes = {}
                    for key, value in user['message_attributes'].items():
                        if isinstance(value, str):
                            formatted_attributes[key] = {
                                'StringValue': value,
                                'DataType': 'String'
                            }
                        elif isinstance(value, (int, float)):
                            formatted_attributes[key] = {
                                'StringValue': str(value),
                                'DataType': 'Number'
                            }
                    entry['MessageAttributes'] = formatted_attributes
                
                if 'delay_seconds' in user:
                    entry['DelaySeconds'] = user['delay_seconds']
                
                entries.append(entry)
            
            response = self.sqs_client.send_message_batch(
                QueueUrl=self.queue_url,
                Entries=entries
            )
            
            for success in response.get('Successful', []):
                results.append({
                    'success': True,
                    'message_id': success['MessageId'],
                    'batch_id': success['Id']
                })
            
            for failure in response.get('Failed', []):
                results.append({
                    'success': False,
                    'batch_id': failure['Id'],
                    'code': failure['Code'],
                    'message': failure['Message']
                })
        
        return results
    
    def publish_user_update_message(
        self,
        user_id: str,
        updated_fields: Dict[str, Any],
        encrypt_pii: bool = True
    ) -> Dict[str, Any]:
        message = {
            'message_id': str(uuid.uuid4()),
            'timestamp': datetime.utcnow().isoformat(),
            'user_id': user_id,
            'message_type': 'user_update',
            'updated_fields': {}
        }
        
        pii_fields = ['email', 'phone_number', 'first_name', 'last_name', 'address']
        
        for field, value in updated_fields.items():
            if field in pii_fields and encrypt_pii:
                if field == 'address' and isinstance(value, dict):
                    message['updated_fields'][field] = {
                        k: self._encrypt_pii_field(str(v)) for k, v in value.items()
                    }
                else:
                    message['updated_fields'][field] = self._encrypt_pii_field(str(value))
            else:
                message['updated_fields'][field] = value
        
        response = self.sqs_client.send_message(
            QueueUrl=self.queue_url,
            MessageBody=json.dumps(message),
            MessageAttributes={
                'MessageType': {
                    'StringValue': 'user_update',
                    'DataType': 'String'
                },
                'UserId': {
                    'StringValue': user_id,
                    'DataType': 'String'
                }
            }
        )
        
        return {
            'message_id': response['MessageId'],
            'user_message_id': message['message_id']
        }
    
    def publish_user_deletion_message(
        self,
        user_id: str,
        email: str,
        reason: str = 'user_requested'
    ) -> Dict[str, Any]:
        message = {
            'message_id': str(uuid.uuid4()),
            'timestamp': datetime.utcnow().isoformat(),
            'user_id': user_id,
            'message_type': 'user_deletion',
            'email_hash': self._hash_pii_field(email),
            'deletion_reason': reason
        }
        
        response = self.sqs_client.send_message(
            QueueUrl=self.queue_url,
            MessageBody=json.dumps(message),
            MessageAttributes={
                'MessageType': {
                    'StringValue': 'user_deletion',
                    'DataType': 'String'
                },
                'UserId': {
                    'StringValue': user_id,
                    'DataType': 'String'
                }
            }
        )
        
        return {
            'message_id': response['MessageId'],
            'user_message_id': message['message_id']
        }
    
    def get_queue_attributes(self) -> Dict[str, Any]:
        response = self.sqs_client.get_queue_attributes(
            QueueUrl=self.queue_url,
            AttributeNames=['All']
        )
        return response['Attributes']
    
    def purge_queue(self) -> None:
        self.sqs_client.purge_queue(QueueUrl=self.queue_url)


